import { asset, defineApertureConfig } from "@aperture-engine/app/config";

export default defineApertureConfig({
  mode: "browser",
  assets: {
    // Load all 11 GLBs (aperture auto-generates material for embedded textures)
    vehicleYellow: asset.gltf("/models/vehicle-truck-yellow.glb"),
    vehicleGreen: asset.gltf("/models/vehicle-truck-green.glb"),
    trackStraight: asset.gltf("/models/track-straight.glb"),
    // ... 8 more GLBs
  },
  // ... rest of config
});

// In a system:
export class TrackSystem {
  update() {
    const vehicleAsset = this.assets.gltf("vehicleYellow");
    if (!vehicleAsset.ready.value) return;

    // Spawn with scale applied via transform
    const vehicle = this.spawn.gltf(vehicleAsset, {
      transform: { scale: [0.5, 0.5, 0.5] },
    });
  }
}

// For material side control (two-sided faces):
// All aperture-loaded GLTFs read doubleSided from glTF JSON.
// If not in GLB, must wrap in custom-wgsl material at spawn time:
const meshEnt = this.spawn.mesh({
  mesh: meshHandle,
  material: material.standard({
    baseColor: [1, 1, 1, 1],
    roughness: 0.8,
  }),
  transform: { ... },
});

// Material side is auto-derived from gltf.doubleSided:
//   doubleSided: true  → cullMode: "none" (both faces visible)
//   doubleSided: false → cullMode: "back" (front-face only, standard)

Aperture provides automatic GPU instancing via two mechanisms:

1. **Automatic batching** (recommended for most cases):
   - Spawn multiple gltf entities with the same mesh/material using `this.spawn.gltf()` in a loop
   - Aperture automatically coalesces consecutive entities sharing mesh, material, pipeline, and mesh layout into a single GPU instanced draw call
   - Each entity gets a separate LocalTransform component; transforms are packed contiguously into a GPU buffer (16 floats = 4x4 matrix per entity)
   - The render extraction detects sequential transform offsets and merges them into one draw with `instanceCount > 1`

Example code (races racing game decorations):
```typescript
// In a system init():
for (const [x, z, type, rotation] of DECO_CELLS) {
  const entity = this.spawn.gltf(this.assets.gltf(type), {
    key: `deco.${type}.${x}.${z}`,
    transform: {
      translation: [x * CELL_SIZE, 0.5, z * CELL_SIZE],
      rotationEulerDegrees: [0, rotation * 90, 0],
    },
  });
  // Optional: add InstanceTint if per-instance color variation is needed
  if (wantVariation) {
    entity.addComponent(InstanceTint, { color: getRandomColor() });
  }
}
```

2. **Explicit per-instance attributes** (for tint/color variation):
   - Add InstanceTint component to entities for per-instance color variations
   - The component is packed into a separate GPU buffer and indexed alongside the instanced draw
   - All 300+ instances with InstanceTint still render as a single draw call with the tint buffer fetched per-instance

```typescript
import { InstanceTint } from "@aperture-engine/render";

entity.addComponent(InstanceTint, {
  color: [r, g, b, a]  // Per-instance tint color
});
```

This matches the reference's THREE.InstancedMesh pattern: one draw call with N instances, each with its own transform and optional per-instance color.

## Scene Background / Clear Color

Aperture supports scene clear color via the camera's `clearColor` property in spawn API:

```typescript
import { createSystem } from "@aperture-engine/app/systems";

export default class SetupSystem extends createSystem({ priority: 0 }) {
  override init(): void {
    this.spawn.camera({
      transform: { translation: [0, 0, 5] },
      camera: {
        clearColor: [0.68, 0.70, 0.73, 1],  // [R, G, B, A] normalized
      },
    });
  }
}
```

Or globally in `aperture.config.ts`:

```typescript
export default defineApertureConfig({
  mode: "browser",
  render: {
    clearColor: [0.68, 0.70, 0.73, 1],
  },
});
```

## Directional and Ambient Lights

Spawned via `this.spawn.light()` with `kind: "directional"` or `kind: "ambient"`:

```typescript
// Directional light with shadows
this.spawn.light({
  key: "light.sun",
  kind: "directional",
  color: [1, 0.96, 0.88, 1],
  illuminance: 7.8,  // convenience alias for intensity
  transform: { rotationEulerDegrees: [-48, 34, 0] },
});

// Ambient fill light
this.spawn.light({
  key: "light.sky",
  kind: "ambient",
  color: [0.72, 0.84, 1, 1],
  intensity: 0.78,
});
```

## Fog (Linear, Exponential, Exponential-Squared)

Fog is supported in the render pipeline. Spawn via manual ECS entity creation:

```typescript
import { createSystem } from "@aperture-engine/app/systems";
import { Fog } from "@aperture-engine/render";

export default class FogSystem extends createSystem({ priority: 0 }) {
  override init(): void {
    const entity = this.createEntity();
    entity.addComponent(Fog, {
      mode: "linear",        // "linear" | "exp" | "exp2"
      color: [0.68, 0.70, 0.73, 1],
      start: 30,             // near distance for linear fog
      end: 55,               // far distance for linear fog
      density: 0.08,         // for exp/exp2 modes only
    });
  }
}
```

Alternatively, use the render module's `createFog()` helper for proper type safety:

```typescript
import { Fog, createFog } from "@aperture-engine/render";

const entity = this.createEntity();
entity.addComponent(Fog, createFog({
  mode: "linear",
  color: [0.68, 0.70, 0.73, 1],
  start: 30,
  end: 55,
}));
```

To enable shadow mapping on a directional light in aperture, spawn a light and then add shadow settings:

```typescript
// In a system's init() or update()
const lightEntity = this.spawn.light({
  name: "sun",
  kind: "directional",
  color: [1, 0.96, 0.88, 1],
  illuminance: 7.8,
  transform: {
    rotationEulerDegrees: [-48, 34, 0],
  },
});

// Then apply shadow settings via a system initializer or direct component addition
lightEntity.addComponent(LightShadowSettings, createLightShadowSettings({
  enabled: true,
  mapSize: 4096,
  bias: 0,
  normalBias: 0,
  cascadeCount: 1,
  casterLayerMask: -1,
  receiverLayerMask: -1,
  shadowType: 1,        // 0=hard, 1=PCF (default), 2=PCSS
  strength: 1,
  filterRadius: 4,      // Maps to three.js shadow.radius (PCF softness)
  slopeBias: 0,
}));

// Mark meshes to cast/receive shadows
for (const meshEntity of meshes) {
  meshEntity.addComponent(ShadowCaster, { enabled: true });
  meshEntity.addComponent(ShadowReceiver, { enabled: true });
}
```

Alternatively, use the runtime initializer form:

```typescript
this.spawn.light({...}, 
  withLightShadowSettings({
    enabled: true,
    mapSize: 4096,
    filterRadius: 4,
  }),
  withShadowCaster(true),
);
```

Aperture provides full support for tonemapping, exposure, and bloom post-effects. To port the three.js racing app:

1. **Enable HDR scene buffer + exposure:**
   Pass `exposure: 1.0` to `createWebGpuApp()`. This renders the scene into rgba16float, applies exposure, tonemap, and sRGB encoding in a final post-stage.

2. **Select tonemap operator:**
   Pass `tonemap: "aces"` to `createWebGpuApp()`. The ACES implementation in aperture uses the standard Filmic tone curve: `(color * (2.51 * color + 0.03)) / (color * (2.43 * color + 0.59) + 0.14)`.

3. **Add bloom post-effect:**
   Import `createWebGpuBloomPostEffect` from `@aperture-engine/webgpu` and add it to the `postEffects` array passed to `createWebGpuApp()`.

Example app setup in browser:
\`\`\`ts
import { startGeneratedBrowserApp } from '@aperture-engine/app/browser';
import { createWebGpuBloomPostEffect } from '@aperture-engine/webgpu';

const app = await startGeneratedBrowserApp({
  config: aperture.config,
  workerEntry: '/path/to/systems.worker.js',
});

// Then pass postEffects when creating the WebGPU app separately, or:
// Use advanced createWebGpuApp directly:

import { createWebGpuApp } from '@aperture-engine/webgpu';

const webgpu = await createWebGpuApp({
  canvas,
  simulationWorker,
  sourceAssets,
  exposure: 1.0,
  tonemap: 'aces',
  postEffects: [
    createWebGpuBloomPostEffect({
      threshold: 0.5,
      intensity: 0.75,  // Default 0.75; UnrealBloomPass strength: 0.02 approx → 0.4-0.8 range here
      radius: 0.02, // Default 0; normalized BloomNode/UnrealBloom radius in 0..1
      levels: 5, // Default 5; BloomNode mip chain depth
    }),
  ],
});
\`\`\`

Aperture provides Image-Based Lighting (IBL) through environment lights, which approximate soft ambient GI from a single environment map. Spawn an environment light referencing a baked HDR environment map:

```typescript
// In your system's init() or spawn phase:
this.spawn.light({
  kind: "environment",
  color: [1, 1, 1, 1],
  intensity: 1.0,
  light: {
    environmentMap: environmentMapHandle, // from preloaded HDR asset
  },
});
```

For spatial variation, combine this with an ambient light for base illumination:

```typescript
this.spawn.light({
  kind: "ambient",
  color: [0.8, 0.9, 1, 1],
  intensity: 0.5,
});
```

Environment maps can be provided as HDR assets in aperture.config.ts and loaded via the asset system. The render backend automatically convolves the environment into diffuse (irradiance) and specular (PMREM) components for PBR materials.

Import physics components and access from `@aperture-engine/app/systems`. Author dynamic bodies with RigidBody (type="dynamic"), Collider (shape="sphere"), and PhysicsVelocity components:

```typescript
import { 
  RigidBody, 
  Collider, 
  PhysicsVelocity,
  createRigidBody,
  createCollider,
  createPhysicsVelocity
} from "@aperture-engine/app/systems";

// In system or level authoring:
entity.addComponent(RigidBody, createRigidBody({
  type: "dynamic",
  gravityScale: 1.5,
  linearDamping: 0.1,
  angularDamping: 4.0,
  ccdEnabled: true,
}));

entity.addComponent(Collider, createCollider({
  shape: { kind: "sphere", radius: 0.5 }
}));

entity.addComponent(PhysicsVelocity, createPhysicsVelocity({
  linear: [0, 0, 0],
  angular: [0, 0, 0]
}));

// Static box colliders via Collider component:
staticEntity.addComponent(Collider, createCollider({
  shape: { kind: "box", halfExtents: [1, 1, 1] },
  offsetRotation: quat, // supports rotation via quaternion
  friction: 0.0,
  restitution: 0.1
