**Option B: Custom CPU-side particle system (interactive, requires authoring)**

```typescript
// Define a CPU particle pool component
import { defineComponent, EcsType } from "@aperture-engine/app/systems";

const ParticleBatchPool = defineComponent({
  positions: EcsType.F32Array,  // 3 floats per particle
  opacities: EcsType.F32Array,  // 1 float per particle
  sizes: EcsType.F32Array,      // 1 float per particle
  velocities: EcsType.F32Array, // 3 floats per particle
  lifetimes: EcsType.F32Array,  // 1 float per particle
  maxLife: EcsType.Float32,
  emitIndex: EcsType.Uint32,
});

export default class SmokePoolSystem extends createSystem({
  priority: 100,
  queries: {
    pools: { required: [ParticleBatchPool] },
    emitters: { required: [WorldTransform] }, // find drift sources
  },
}) {
  override init() {
    const poolEntity = this.createEntity();
    const poolSize = 1280;

    poolEntity.addComponent(ParticleBatchPool, {
      positions: new Float32Array(poolSize * 3),
      opacities: new Float32Array(poolSize),
      sizes: new Float32Array(poolSize),
      velocities: new Float32Array(poolSize * 3),
      lifetimes: new Float32Array(poolSize),
      maxLife: 2.5,
      emitIndex: 0,
    });
  }

  override update(dt: number) {
    const pool = this.queries.pools.entities[0]?.getValue(ParticleBatchPool);
    if (!pool) return;

    // Update particle lifetimes, positions, opacities, sizes
    const damping = 1 - dt;
    for (let i = 0; i < pool.positions.length / 3; i++) {
      if (pool.lifetimes[i] <= 0) continue;

      pool.lifetimes[i] -= dt;
      pool.velocities[i * 3] *= damping; // velocity decay

      pool.positions[i * 3] += pool.velocities[i * 3] * dt;
      pool.positions[i * 3 + 1] += pool.velocities[i * 3 + 1] * dt;

      const t = 1 - (pool.lifetimes[i] / pool.maxLife);
      pool.opacities[i] = (1 - t) * 0.25;
      pool.sizes[i] = pool.sizes[i] * (0.5 + t * 2.5);
    }
  }

  emit(x: number, y: number, z: number) {
    const pool = this.queries.pools.entities[0]?.getValue(ParticleBatchPool);
    if (!pool) return;

    const i = pool.emitIndex;
    pool.emitIndex = (i + 1) % (pool.positions.length / 3);

    pool.positions[i * 3] = x;
    pool.positions[i * 3 + 1] = y;
    pool.positions[i * 3 + 2] = z;
    pool.velocities[i * 3] = (Math.random() - 0.5) * 0.2;
    pool.velocities[i * 3 + 1] = 0.5 + Math.random() * 0.5;
    pool.velocities[i * 3 + 2] = (Math.random() - 0.5) * 0.2;
    pool.lifetimes[i] = pool.maxLife;
    pool.sizes[i] = 0.5 + Math.random() * 0.5;
  }
}
```

