  kind: "mesh",
  label: "drift-trail",
  vertexStreams: [
    {
      id: "interleaved",
      arrayStride: 28, // 3 floats (pos) + 1 float padding + 4 floats (RGBA) + 4 floats (normal, dummy)
      vertexCount: maxVertices,
      attributes: [
        { semantic: "POSITION", format: "float32x3", offset: 0 },
        { semantic: "NORMAL", format: "float32x3", offset: 12 }, // dummy
        { semantic: "TEXCOORD_0", format: "float32x2", offset: 24 }, // dummy
        { semantic: "COLOR_0", format: "float32x4", offset: 32 } // actual color data
      ],
      data: interleavedBuffer // app writes positions and colors here
