    const player = this.#findNamedEntity("player");
    const camera = this.#findNamedEntity("main-camera");
    if (!player || !camera) return;

    const playerPos = player.getVectorView(LocalTransform, "translation");
    const cameraTransform = camera.getVectorView(LocalTransform, "translation");

    // Compute target position with velocity lead and deadzone clamping
    // (racing reference: lead = velocity dot camera-aligned basis, clamped to deadzoneRadius)
    const targetX = /* computed */;
    const targetY = /* computed */;
    const targetZ = CAMERA.distance;

    // Smooth lerp
    const nextX = lerp(cameraTransform[0], targetX, CAMERA.smoothing);
    const nextY = lerp(cameraTransform[1], targetY, CAMERA.smoothing);
    cameraTransform.set([nextX, nextY, targetZ]);

