## System: Lap Timer (src/systems/lap-timer.system.ts)
Run per-frame logic with delta + read entity world position:

```typescript
import { createSystem, LocalTransform, WorldTransform, Name } from '@aperture-engine/app/systems';
import { CELL_RAW, GRID_SCALE, computeSpawnPosition } from '../lib/track.js';

export default class LapTimerSystem extends createSystem({
  priority: 50, // after physics, before render
  queries: {
    actors: { required: [Name, LocalTransform] }
  }
}) {
  #lapState = { running: false, currentTime: 0, bestLap: null };
  #prevForwardProj: number | null = null;
  #visitedCells = new Set<string>();
  #requiredCells: Set<string>;

  override init(): void {
    const mapParam = new URLSearchParams(window.location.search).get('map');
    const cells = mapParam ? decodeCells(mapParam) : DEFAULT_CELLS;
    this.#requiredCells = new Set(
      cells.filter(c => c.type !== 'track-finish')
        .map(c => `${c.gx},${c.gz}`)
    );
    this.#loadBestLap();
  }

  override update(delta: number, time: number): void {
    const player = this.#findPlayer();
    if (!player) return;

    // Read world position from LocalTransform
    const pos = player.getVectorView(LocalTransform, 'translation');
    const playerX = pos[0], playerZ = pos[2];

    // Grid cell tracking
    const gx = Math.floor(playerX / (CELL_RAW * GRID_SCALE));
    const gz = Math.floor(playerZ / (CELL_RAW * GRID_SCALE));
    this.#visitedCells.add(`${gx},${gz}`);

    // Finish line crossing detection (dot product against forward vector)
    const forwardProj = /* ... project position to finish line ... */;
    if (this.#prevForwardProj !== null) {
      const crossedLine = this.#prevForwardProj < 0 && forwardProj >= 0;
      const allCellsVisited = this.#visitedCells.size === this.#requiredCells.size;
      if (crossedLine && allCellsVisited) {
        this.#completeLap(this.#lapState.currentTime);
      }
    }
    this.#prevForwardProj = forwardProj;

    // Update signals
    this.signals.lapTime.value = this.#lapState.currentTime;
    this.signals.bestLap.value = this.#lapState.bestLap;
  }

  #findPlayer() {
    for (const entity of this.queries.actors.entities) {
      if (entity.getValue(Name, 'value') === 'player-vehicle') return entity;
    }
    return null;
  }

  #completeLap(time: number): void {
    const isBest = this.#lapState.bestLap === null || time < this.#lapState.bestLap;
    this.#lapState.bestLap = isBest ? time : this.#lapState.bestLap;
    this.#saveBestLap();
    this.#lapState.currentTime = 0;
    this.#visitedCells.clear();
    this.signals.lapCompleted.value = isBest ? 'best' : 'clear';
  }

  #loadBestLap(): void {
    try {
      const key = 'racing.bestLap.' + (/* track id */);
      const v = localStorage.getItem(key);
      this.#lapState.bestLap = v ? Number(v) : null;
    } catch {}
  }

  #saveBestLap(): void {
    try {
      const key = 'racing.bestLap.' + (/* track id */);
      localStorage.setItem(key, String(this.#lapState.bestLap));
    } catch {}
  }
}
```

