The track spawn system (separate from lap timer) uses standard aperture spawn API:

```typescript
export default class TrackSpawnSystem extends createSystem({ priority: 10 }) {
  override init(): void {
    const mapParam = new URLSearchParams(window.location.search).get('map');
    const cells = mapParam ? decodeCells(mapParam) : DEFAULT_CELLS;

    for (const cell of cells) {
      const pos = cellToWorldPos(cell);
      this.spawn.gltf(this.assets.gltf(cell.type), {
        key: `track.${cell.gx}.${cell.gz}`,
        transform: { translation: pos, /* rotation from cell.orient */ }
      });
    }
  }
}
